   641→		}
   642→	}
   643→
   644→	return newSettings
   645→}
   646→
   647→func deepCopySlice(s []any) []any {
   648→	newSlice := make([]any, len(s))
   649→
   650→	for i, value := range s {
   651→		switch v := value.(type) {
   652→		case map[string]any:
   653→			newSlice[i] = deepCopyMap(v)
   654→		case []any:
   655→			newSlice[i] = deepCopySlice(v)
   656→		default:
   657→			newSlice[i] = value
   658→		}
   659→	}
   660→
   661→	return newSlice
   662→}
